name = "Superior Fool",
	key = "supfool",
	set = "Superior",
	atlas = "Superior",
	crv_in_set = "Tarot",

	pos = {
		x = 0,
		y = 0,
	},
	discovered = true,
	config = {
		extra = { cards = nil },
	},
	pools = {
		SuperiorTarot = true,
	},
	loc_vars = function(self, info_queue, card)
		local joka
		local c
		if G.GAME.dont_question then
			joka = localize({ type = "name_text", key = G.GAME.dont_question, set = "Joker" })
			c = G.C.GREEN
		else
			joka = localize("k_none")
			c = G.C.RED
		end
		if G.GAME.dont_question then
			info_queue[#info_queue+1] = G.P_CENTERS[G.GAME.dont_question]
		end
		return {
			main_end = {
				{
					n = G.UIT.C,
					config = { align = "bm", padding = 0.02 },
					nodes = {
						{
							n = G.UIT.C,
							config = { align = "m", colour = c, r = 0.05, padding = 0.05 },
							nodes = {
								{
									n = G.UIT.T,
									config = {
										text = " " .. joka .. " ",
										colour = G.C.UI.TEXT_LIGHT,
										scale = 0.3,
										shadow = true,
									},
								},
							},
						},
					},
				},
			},
			vars = {},
		}
	end,
	can_use = function(self, card)
		if G and G.GAME and G.GAME.last_destroyed_joker and RevosVault.has_room(G.jokers) then
			return true
		end
		return false
	end,
	use = function(self, card, area, copier)
		SMODS.add_card({
			key = G.GAME.dont_question,
		})
	end,

key = "supmagician",
	set = "Superior",
	atlas = "Superior",
	crv_in_set = "Tarot",

	pos = {
		x = 1,
		y = 0,
	},
	discovered = true,
	config = {
		max_highlighted = 3,
		min_highlighted = 1,
		extra = {},
	},
	pools = {
		SuperiorTarot = true,
	},
	loc_vars = function(self, info_queue, card)
		return { vars = { self.config.max_highlighted, card.ability.extra.cards } }
	end,
	use = function(self, card, area, copier)
		for _, v in pairs(G.hand.highlighted) do
			v:flip()
			G.E_MANAGER:add_event(Event({
				trigger = "before",
				delay = 0.2,
				func = function()
					v:set_ability("m_lucky")
					return true
				end,
			}))
			G.E_MANAGER:add_event(Event({
				trigger = "after",
				delay = 0.2,
				func = function()
					v:flip()
					G.hand:unhighlight_all()
					return true
				end,
			}))
		end
	end,
	calculate = function(self, card, context)
		if context.repetition and context.cardarea == G.play then
			if SMODS.has_enhancement(context.other_card, "m_lucky") then
				return {
					repetitions = 1,
				}
			end
		end
	end,

key = "suphigh_priestess",
	set = "Superior",
	atlas = "Superior",
	crv_in_set = "Tarot",

	pos = {
		x = 2,
		y = 0,
	},
	discovered = true,
	config = {
		extra = { create = 3 },
	},
	pools = {
		SuperiorTarot = true,
	},
	loc_vars = function(self, info_queue, card)
		return { vars = { card.ability.extra.create } }
	end,
	can_use = function(self, card)
		return true
	end,
	use = function(self, card, area, copier)
		local _planet, _hand = nil, RevosVault.most_played()
		for _, v in pairs(G.P_CENTER_POOLS.Planet) do
			if v.config.hand_type == _hand then
				_planet = v.key
			end
		end
		for i = 1, card.ability.extra.create do
			SMODS.add_card({
				key = _planet,
				edition = "e_negative",
			})
		end
	end,

