key = "suphermit",
	set = "Superior",
	atlas = "Superior",
	crv_in_set = "Tarot",

	pos = {
		x = 9,
		y = 0,
	},
	discovered = true,
	config = {
		extra = {
			money = 100,
			give = 5,
		},
	},
	pools = {
		SuperiorTarot = true,
	},
	loc_vars = function(self, info_queue, card)
		return { vars = { card.ability.extra.money, card.ability.extra.give } }
	end,
	can_use = function(self, card)
		return true
	end,
	use = function(self, card, area, copier)
		G.E_MANAGER:add_event(Event({
			trigger = "after",
			delay = 0.4,
			func = function()
				play_sound("timpani")
				card:juice_up(0.3, 0.5)
				ease_dollars(math.max(0, math.min(G.GAME.dollars + G.GAME.dollars, card.ability.extra.money)), true)
				return true
			end,
		}))
	end,
	calculate = function(self, card, context)
		if context.end_of_round and context.main_eval then
			return {
				dollars = card.ability.extra.give,
			}
		end
	end,

key = "supwheel_of_fortune",
	set = "Superior",
	atlas = "Superior",
	crv_in_set = "Tarot",

	pos = {
		x = 0,
		y = 1,
	},
	discovered = true,
	config = {
		extra = {},
	},
	pools = {
		SuperiorTarot = true,
	},
	loc_vars = function(self, info_queue, card)
		return { vars = {} }
	end,
	can_use = function(self, card)
		local jokas = {}
		for i = 1, #G.jokers.cards do
			if not G.jokers.cards[i].edition then
				jokas[#jokas + 1] = G.jokers.cards[i]
			end
		end
		if #G.jokers.cards > 0 and #jokas > 0 then
			return true
		end
	end,
	use = function(self, card, area, copier)
		RevosVault.wheeloffortune(1, G.jokers.cards)
	end,

