key = "suphanged_man",
	set = "Superior",
	atlas = "Superior",
	crv_in_set = "Tarot",

	pos = {
		x = 2,
		y = 1,
	},
	pools = {
		SuperiorTarot = true,
	},
	discovered = true,
	config = {
		max_highlighted = 5,
		min_highlighted = 1,
		extra = {
			chips = 0,
		},
	},
	loc_vars = function(self, info_queue, card)
		if G and G.GAME then
			return { vars = { self.config.max_highlighted, card.ability.extra.chips } }
		else
			return { vars = { self.config.max_highlighted, G.GAME.hangedmanchips } }
		end
	end,
	use = function(self, card, area, copier)
		for _, v in pairs(G.hand.highlighted) do
			G.GAME.hangedmanchips = G.GAME.hangedmanchips + v.base.id
			SMODS.destroy_cards(v)
		end
	end,
	calculate = function(self, card, context)
		if context.joker_main then
			return {
				chips = G.GAME.hangedmanchips,
			}
		end
	end,

key = "supdeath",
	set = "Superior",
	atlas = "Superior",
